"use strict";import H from"../../Core/Globals.js";var noop=H.noop;import VerletIntegration from"../Networkgraph/VerletIntegration.js";function barycenter(){for(var e,t=this,r=t.options.gravitationalConstant,o=t.box,i=t.nodes,n=0,a=i;n<a.length;n++){var s=a[n],l=t.options.splitSeries&&!s.isParentNode?(e=s.series.parentNode.plotX,s.series.parentNode.plotY):(e=o.width/2,o.height/2);s.fixedPosition||(s.plotX-=(s.plotX-e)*r/(s.mass*Math.sqrt(i.length)),s.plotY-=(s.plotY-l)*r/(s.mass*Math.sqrt(i.length)))}}function repulsive(e,t,r,o){var t=t*this.diffTemperature/e.mass/e.degree,i=r.x*t,r=r.y*t;e.fixedPosition||(e.plotX+=i,e.plotY+=r),o.fixedPosition||(o.plotX-=i,o.plotY-=r)}function repulsiveForceFunction(e,t,r,o){return Math.min(e,(r.marker.radius+o.marker.radius)/2)}var PackedBubbleIntegration={barycenter:barycenter,getK:noop,integrate:VerletIntegration.integrate,repulsive:repulsive,repulsiveForceFunction:repulsiveForceFunction};export default PackedBubbleIntegration;